 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { computeNamedRegions, NamedRegion } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

interface ExpectedNamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

function assertNamedRegions(lines: string[], expected: ExpectedNamedRegion[]): void {
	const model = createTextModel(lines.join('\n'));
	const namedRegions: NamedRegion[] = [];
	const foldingLimitReporter = { limit: 5000, update: () => { } };

	computeNamedRegions(model, foldingLimitReporter, namedRegions);

	const actualRegions: ExpectedNamedRegion[] = namedRegions.map(r => ({
		name: r.name,
		startLineNumber: r.startLineNumber,
		endLineNumber: r.endLineNumber
	}));

	assert.deepStrictEqual(actualRegions, expected, `Expected regions: ${JSON.stringify(expected)}, but got: ${JSON.stringify(actualRegions)}`);
	model.dispose();
}

suite('Named Region Folding', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detect single named region', () => {
		const lines = [
			'// #region MySection',
			'function foo() {',
			'  console.log("hello");',
			'}',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'MySection', startLineNumber: 1, endLineNumber: 5 }
		]);
	});

	test('Detect multiple named regions', () => {
		const lines = [
			'// #region FirstRegion',
			'function foo() {}',
			'// #endregion',
			'// #region SecondRegion',
			'function bar() {}',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'FirstRegion', startLineNumber: 1, endLineNumber: 3 },
			{ name: 'SecondRegion', startLineNumber: 4, endLineNumber: 6 }
		]);
	});

	test('Detect nested regions', () => {
		const lines = [
			'// #region Outer',
			'  // #region Inner',
			'  function foo() {}',
			'  // #endregion',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'Inner', startLineNumber: 2, endLineNumber: 4 },
			{ name: 'Outer', startLineNumber: 1, endLineNumber: 5 }
		]);
	});

	test('Extract region name from marker', () => {
		const lines = [
			'// #region Helpers and Utilities',
			'function helper1() {}',
			'function helper2() {}',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'Helpers and Utilities', startLineNumber: 1, endLineNumber: 4 }
		]);
	});

	test('Handle region without explicit end', () => {
		const lines = [
			'// #region UnfinishedRegion',
			'function foo() {}',
			'function bar() {}',
			'// some other code'
		];
		assertNamedRegions(lines, [
			{ name: 'UnfinishedRegion', startLineNumber: 1, endLineNumber: 4 }
		]);
	});

	test('Handle endregion without corresponding start', () => {
		const lines = [
			'function foo() {}',
			'// #endregion',
			'function bar() {}'
		];
		assertNamedRegions(lines, []);
	});

	test('Handle region with just #region keyword', () => {
		const lines = [
			'// #region',
			'function foo() {}',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ name: 'Region', startLineNumber: 1, endLineNumber: 3 }
		]);
	});

	test('Ignore regions with less than 1 line span', () => {
		const lines = [
			'// #region Empty',
			'// #endregion'
		];
		assertNamedRegions(lines, []);
	});
});

