253: 		this.localToDispose.add(this.editor.onMouseUp(e => this.onEditorMouseUp(e)));
254: 		this.localToDispose.add({
255: 			dispose: () => {
256: 				if (this.foldingRegionPromise) {
257: 					this.foldingRegionPromise.cancel();
258: 					this.foldingRegionPromise = null;
259: 				}
260: 				this.updateScheduler?.cancel();
261: 				this.updateScheduler = null;
262: 				this.foldingModel = null;
263: 				this.foldingModelPromise = null;
264: 				this.hiddenRangeModel = null;
265: 				this.cursorChangedScheduler = null;
266: 				this.rangeProvider?.dispose();
267: 				this.rangeProvider = null;
