304: 	public triggerFoldingModelChanged() {
305: 		if (this.updateScheduler) {
306: 			if (this.foldingRegionPromise) {
307: 				this.foldingRegionPromise.cancel();
308: 				this.foldingRegionPromise = null;
309: 			}
310: 			this.foldingModelPromise = this.updateScheduler.trigger(() => {
311: 				const foldingModel = this.foldingModel;
312: 				if (!foldingModel) { // null if editor has been disposed, or folding turned off
313: 					return null;
314: 				}
315: 				const sw = new StopWatch();
316: 				const provider = this.getRangeProvider(foldingModel.textModel);
317: 				const foldingRegionPromise = this.foldingRegionPromise = createCancelablePromise(token => provider.compute(token));
318: 				return foldingRegionPromise.then(foldingRanges => {
319: 					if (foldingRanges && foldingRegionPromise === this.foldingRegionPromise) { // new request or cancelled in the meantime?
320: 						let scrollState: StableEditorScrollState | undefined;
321: 
322: 						if (this._foldingImportsByDefault && !this._currentModelHasFoldedImports) {
323: 							const hasChanges = foldingRanges.setCollapsedAllOfType(FoldingRangeKind.Imports.value, true);
324: 							if (hasChanges) {
325: 								scrollState = StableEditorScrollState.capture(this.editor);
326: 								this._currentModelHasFoldedImports = hasChanges;
327: 							}
328: 						}
329: 
330: 						// some cursors might have moved into hidden regions, make sure they are in expanded regions
331: 						const selections = this.editor.getSelections();
332: 						foldingModel.update(foldingRanges, toSelectedLines(selections));
333: 
334: 						scrollState?.restore(this.editor);
335: 
336: 						// update debounce info
337: 						const newValue = this.updateDebounceInfo.update(foldingModel.textModel, sw.elapsed());
338: 						if (this.updateScheduler) {
339: 							this.updateScheduler.defaultDelay = newValue;
340: 						}
341: 					}
342: 					return foldingModel;
343: 				});
344: 			}).then(undefined, (err) => {
345: 				onUnexpectedError(err);
346: 				return null;
347: 			});
348: 		}
349: 	}
