371: 		if (!foldingModel) {
372: 			return;
373: 		}
374: 		foldingModel.then(foldingModel => { // null is returned if folding got disabled in the meantime
375: 			if (foldingModel) {
376: 				const selections = this.editor.getSelections();
377: 				if (selections && selections.length > 0) {
378: 					const toToggle: FoldingRegion[] = [];
379: 					for (const selection of selections) {
380: 						const lineNumber = selection.selectionStartLineNumber;
381: 						if (this.hiddenRangeModel && this.hiddenRangeModel.isHidden(lineNumber)) {
382: 							toToggle.push(...foldingModel.getAllRegionsAtLine(lineNumber, r => r.isCollapsed && lineNumber > r.startLineNumber));
383: 						}
384: 					}
385: 					if (toToggle.length) {
386: 						foldingModel.toggleCollapseState(toToggle);
387: 						this.reveal(selections[0].getPosition());
388: 					}
389: 				}
390: 			}
