395: 	private onEditorMouseDown(e: IEditorMouseEvent): void {
396: 		this.mouseDownInfo = null;
397: 
398: 
399: 		if (!this.hiddenRangeModel || !e.target || !e.target.range) {
400: 			return;
401: 		}
402: 		if (!e.event.leftButton && !e.event.middleButton) {
403: 			return;
404: 		}
405: 		const range = e.target.range;
406: 		let iconClicked = false;
407: 		switch (e.target.type) {
408: 			case MouseTargetType.GUTTER_LINE_DECORATIONS: {
409: 				const data = e.target.detail;
410: 				const offsetLeftInGutter = e.target.element!.offsetLeft;
411: 				const gutterOffsetX = data.offsetX - offsetLeftInGutter;
412: 
413: 				// const gutterOffsetX = data.offsetX - data.glyphMarginWidth - data.lineNumbersWidth - data.glyphMarginLeft;
414: 
415: 				// TODO@joao TODO@alex TODO@martin this is such that we don't collide with dirty diff
416: 				if (gutterOffsetX < 4) { // the whitespace between the border and the real folding icon border is 4px
417: 					return;
418: 				}
419: 
420: 				iconClicked = true;
421: 				break;
422: 			}
423: 			case MouseTargetType.CONTENT_EMPTY: {
424: 				if (this._unfoldOnClickAfterEndOfLine && this.hiddenRangeModel.hasRanges()) {
425: 					const data = e.target.detail;
426: 					if (!data.isAfterLines) {
427: 						break;
428: 					}
429: 				}
430: 				return;
431: 			}
432: 			case MouseTargetType.CONTENT_TEXT: {
433: 				if (this.hiddenRangeModel.hasRanges()) {
434: 					const model = this.editor.getModel();
435: 					if (model && range.startColumn === model.getLineMaxColumn(range.startLineNumber)) {
436: 						break;
437: 					}
438: 				}
439: 				return;
440: 			}
441: 			default:
442: 				return;
443: 		}
444: 
445: 		this.mouseDownInfo = { lineNumber: range.startLineNumber, iconClicked };
446: 	}
447: 
448: 	private onEditorMouseUp(e: IEditorMouseEvent): void {
449: 		const foldingModel = this.foldingModel;
450: 		if (!foldingModel || !this.mouseDownInfo || !e.target) {
451: 			return;
452: 		}
453: 		const lineNumber = this.mouseDownInfo.lineNumber;
454: 		const iconClicked = this.mouseDownInfo.iconClicked;
455: 
456: 		const range = e.target.range;
457: 		if (!range || range.startLineNumber !== lineNumber) {
458: 			return;
459: 		}
460: 
461: 		if (iconClicked) {
462: 			if (e.target.type !== MouseTargetType.GUTTER_LINE_DECORATIONS) {
463: 				return;
464: 			}
465: 		} else {
466: 			const model = this.editor.getModel();
467: 			if (!model || range.startColumn !== model.getLineMaxColumn(lineNumber)) {
468: 				return;
469: 			}
470: 		}
471: 
472: 		const region = foldingModel.getRegionAtLine(lineNumber);
473: 		if (region && region.startLineNumber === lineNumber) {
474: 			const isCollapsed = region.isCollapsed;
475: 			if (iconClicked || isCollapsed) {
476: 				const surrounding = e.event.altKey;
477: 				let toToggle = [];
478: 				if (surrounding) {
479: 					const filter = (otherRegion: FoldingRegion) => !otherRegion.containedBy(region) && !region.containedBy(otherRegion);
480: 					const toMaybeToggle = foldingModel.getRegionsInside(null, filter);
481: 					for (const r of toMaybeToggle) {
482: 						if (r.isCollapsed) {
483: 							toToggle.push(r);
484: 						}
485: 					}
486: 					// if any surrounding regions are folded, unfold those. Otherwise, fold all surrounding
487: 					if (toToggle.length === 0) {
488: 						toToggle = toMaybeToggle;
489: 					}
490: 				}
491: 				else {
492: 					const recursive = e.event.middleButton || e.event.shiftKey;
493: 					if (recursive) {
494: 						for (const r of foldingModel.getRegionsInside(region)) {
495: 							if (r.isCollapsed === isCollapsed) {
496: 								toToggle.push(r);
497: 							}
498: 						}
499: 					}
500: 					// when recursive, first only collapse all children. If all are already folded or there are no children, also fold parent.
501: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/vscode--138f619c@7344a1807afca4c7dbac122b9a8952fd73001f85/-/blob/src/vs/editor/contrib/folding/browser/folding.ts%3FL1-500"}

{"content":"500: 					// when recursive, first only collapse all children. If all are already folded or there are no children, also fold parent.
501: 					if (isCollapsed || !recursive || toToggle.length === 0) {
502: 						toToggle.push(region);
503: 					}
504: 				}
505: 				foldingModel.toggleCollapseState(toToggle);
506: 				this.reveal({ lineNumber, column: 1 });
507: 			}
508: 		}
509: 	}
