731: 			metadata: {
732: 				description: 'Fold the content in the editor',
733: 				args: [
734: 					{
735: 						name: 'Fold editor argument',
736: 						description: `Property-value pairs that can be passed through this argument:
737: 							* 'levels': Number of levels to fold.
738: 							* 'direction': If 'up', folds given number of levels up otherwise folds down.
739: 							* 'selectionLines': Array of the start lines (0-based) of the editor selections to apply the fold action to. If not set, the active selection(s) will be used.
740: 							If no levels or direction is set, folds the region at the locations or if already collapsed, the first uncollapsed parent instead.
741: 						`,
742: 						constraint: foldingArgumentsConstraint,
743: 						schema: {
744: 							'type': 'object',
745: 							'properties': {
746: 								'levels': {
747: 									'type': 'number',
748: 								},
749: 								'direction': {
750: 									'type': 'string',
